(()=>{var o=window.matchMedia("(prefers-color-scheme: dark)");function e(){document.body.classList.toggle("dark",o.matches),document.querySelector("#logo").src=o.matches?"./img/logo-dark.svg":"./img/logo-light.svg",document.querySelector("link[rel=icon]").href=o.matches?"./img/favicon-dark.png":"./img/favicon-light.png"}document.addEventListener("DOMContentLoaded",e);o.addEventListener("change",e);})();
